import httpx, json
from anthropic import Anthropic

client = Anthropic()

SERVICES = {
    "search_agent":  "http://localhost:8001",
    "code_agent":    "http://localhost:8002",
    "writer_agent":  "http://localhost:8003",
}

TOOLS = [
    {
        "name": "search",
        "description": "Search the web and return summarised results for a query.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string"},
                "max_results": {"type": "integer", "default": 5},
            },
            "required": ["query"],
        },
    },
    {
        "name": "run_code",
        "description": "Write and execute Python code. Returns stdout and any generated files.",
        "input_schema": {
            "type": "object",
            "properties": {
                "task": {"type": "string", "description": "What the code should do"},
                "language": {"type": "string", "enum": ["python"], "default": "python"},
            },
            "required": ["task"],
        },
    },
    {
        "name": "write_document",
        "description": "Draft a long-form document (report, email, proposal) given a brief.",
        "input_schema": {
            "type": "object",
            "properties": {
                "brief": {"type": "string"},
                "format": {"type": "string", "enum": ["markdown", "plain"], "default": "markdown"},
            },
            "required": ["brief"],
        },
    },
]

def call_specialist(tool_name: str, inputs: dict) -> str:
    url_map = {
        "search":        (SERVICES["search_agent"],  "/search"),
        "run_code":      (SERVICES["code_agent"],    "/code/run"),
        "write_document":(SERVICES["writer_agent"],  "/write"),
    }
    base, path = url_map[tool_name]
    try:
        resp = httpx.post(f"{base}{path}", json=inputs, timeout=60)
        resp.raise_for_status()
        return resp.text   # already JSON
    except httpx.HTTPError as exc:
        return json.dumps({"error": str(exc), "service": tool_name})

def orchestrator_agent(user_task: str) -> str:
    messages = [{"role": "user", "content": user_task}]
    system = (
        "You are an orchestrator agent. Decompose the user's task into sub-tasks "
        "and call the appropriate specialist agents. Synthesise their outputs into "
        "a final, complete response."
    )
    while True:
        resp = client.messages.create(
            model="claude-sonnet-5",
            max_tokens=1500,
            tools=TOOLS,
            system=system,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if b.type == "text"), "")
        tool_results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = call_specialist(block.name, block.input)
                tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages += [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]

import asyncio, httpx, json
from anthropic import Anthropic

client = Anthropic()

async def call_specialist_async(tool_name: str, inputs: dict) -> str:
    url_map = {
        "search":         "http://localhost:8001/search",
        "run_code":       "http://localhost:8002/code/run",
        "write_document": "http://localhost:8003/write",
    }
    url = url_map.get(tool_name)
    if url is None:
        return json.dumps({"error": "unknown specialist"})
    async with httpx.AsyncClient(timeout=60) as c:
        try:
            resp = await c.post(url, json=inputs)
            resp.raise_for_status()
            return resp.text
        except httpx.HTTPError as exc:
            return json.dumps({"error": str(exc)})

async def orchestrator_async(user_task: str) -> str:
    messages = [{"role": "user", "content": user_task}]
    while True:
        resp = client.messages.create(
            model="claude-sonnet-5",
            max_tokens=1500,
            tools=TOOLS,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next((b.text for b in resp.content if b.type == "text"), "")

        tool_blocks = [b for b in resp.content if b.type == "tool_use"]

        # Run all tool calls in this turn concurrently
        results = await asyncio.gather(
            *[call_specialist_async(b.name, b.input) for b in tool_blocks]
        )

        tool_results = [
            {"type": "tool_result", "tool_use_id": b.id, "content": r}
            for b, r in zip(tool_blocks, results)
        ]
        messages += [
            {"role": "assistant", "content": resp.content},
            {"role": "user", "content": tool_results},
        ]

