import os, httpx, json

# Service registry: populated from environment or a service discovery system
def get_service_registry() -> dict[str, str]:
    return {
        "search":   os.environ.get("SEARCH_AGENT_URL",  "http://localhost:8001"),
        "code":     os.environ.get("CODE_AGENT_URL",    "http://localhost:8002"),
        "writer":   os.environ.get("WRITER_AGENT_URL",  "http://localhost:8003"),
    }

def check_service_health(name: str, base_url: str) -> bool:
    try:
        resp = httpx.get(f"{base_url}/health", timeout=3)
        return resp.status_code == 200
    except httpx.HTTPError:
        return False

def available_specialists() -> list[str]:
    registry = get_service_registry()
    return [name for name, url in registry.items() if check_service_health(name, url)]

# The orchestrator calls available_specialists() at startup and removes tools
# for unhealthy services before passing the tool list to the model.
# This prevents the model from attempting to use an unavailable service.
